var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아저씨! 민우 아저씨 있어요?!","JPN":"おじさん！　マツダおじさんいるー？","ENG":"Mr. Minwoo! Are you here?!","TWN":"叔叔！民宇叔叔在嗎？！"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐야, 없네? 꼭 필요할 때는 자리비움이라니까?","JPN":"なんだ、いないんだ。いつも必要な時に限っていないんだから。","ENG":"Huh? He's not here? Ugh, he's never around when you need him!","TWN":"什麼嘛～不在喔？每次需要他的時候就找不到人！"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그건 네가 시도 때도 없이 찾아오니까 그렇게 느끼는 거지.","JPN":"そりゃあんたがひっきりなしに来るからそう思うだけだろ。","ENG":"That's only because you come here all the time.","TWN":"那是因為你三不五時就來報到，才會有這種感覺。"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"여긴 편의점이다, 레이첼. 물건을 파는 데지 주민 센터가 아니야.","JPN":"ここはコンビニだ、レイチェル。物を売る場所で公民館じゃあない。","ENG":"This is a convenience store, Rachel. We sell stuff here. We're not your mom.","TWN":"我說瑞秋，這裡是便利商店，不是里民活動中心好嗎！"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"편의점 점원이 왜 그렇게 까칠해요. 사포라도 말아 잡수셨나.","JPN":"コンビニの店員がそんな無愛想でいいんですか？　そんなにピリピリしちゃって。","ENG":"Geez, why are you so grouchy? Do you live in a trash can or something?","TWN":"便利商店店員怎麼這麼愛頂嘴，人家講一句你回十句。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"다른 건 몰라도 제가 이 가게에서 스프레이 하나는 잘 팔아 주거든요? 손님 대접은 해 주시죠?","JPN":"他はどうかわからないけど、この店のスプレーに関してはアタシが太客なんですけど！　ちゃんとお客様として接してください！","ENG":"You know how many spray cans I've bought at this place? That's no way to treat a paying customer.","TWN":"其他我不敢說，起碼我也在這家店裡消費不少噴漆好嗎？可以來點客人的待遇嗎？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"안 그래도 주인장이 그러더군.","JPN":"ああ、そういや店長も言ってたな。","ENG":"That's right, the manager told me.","TWN":"人家主人也有跟我抱怨好嗎？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 안 졸라댔으면 그 잡동사니들 들여놓는 일도 없었다고 말이야.","JPN":"あんたがせがまなければ、あんなガラクタを仕入れることもなかったってな。","ENG":"If it wasn't for your little tantrum, he'd never stock that junk.","TWN":"他說要不是你一直吵，他才不會讓你畫那些有的沒的。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"체엣. 뭐래, 그 할배는. 바가지도 실컷 씌워 먹는 주제에.","JPN":"チッ、なんなのあのジジイは。ぼったくり価格で売りつけてるくせに。","ENG":"Hmph. That old geezer's full of it. He's always ripping me off anyway.","TWN":"嗟！說什麼呢！那位爺爺得了便宜還賣乖！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"수다 친구 찾으러 왔다면 다음에 다시 와.","JPN":"おしゃべりの相手がほしいだけなら今度にしろ。","ENG":"If you're here to make small talk, you'll have to come back later.","TWN":"你想來找人聊天的話，晚點再來吧。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"자경단 녀석들이 도와달라고 해서 합류하러 가야 하니까.","JPN":"俺は自警団のやつらに頼まれたからこれから合流しに行く。","ENG":"The neighborhood watch guys needed a hand.","TWN":"自衛隊的人來找我幫忙，我現在要去跟他們會合。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 내 정신 좀 봐! 혹시 그 애 못 봤어요?","JPN":"あ、そうだ、アタシったら！　あの子見てないですか？","ENG":"Oh, I almost forgot! Have you seen that kid by any chance?","TWN":"哎呀！看我這記性！我是要問你有看到她嗎？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"여기서 신세 지는 동안 네가 기저귀 들고 쫓아다니는 애만 일곱 명은 넘게 봤다.","JPN":"ここで働き始めてから、あんたがオムツを持って追いかけてた子どもだけでも7人以上は知っているんだが。","ENG":"I must have seen at least half dozen of those kids you're always chasing around here.","TWN":"我每天看你拿著尿布追著一堆人跑，誰知道你在問誰？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"언제 그렇게 보고 계셨대. 음흉하게시리.","JPN":"そんなにアタシのことを見てたんですか？　いやらしい。","ENG":"Oh, so you've been keeping tabs? Creepy.","TWN":"就是那個每次眼神都很不懷好意的那個嘛！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……급한 볼일 아니면 그만 가라.","JPN":"……他に用事がないなら帰ってくれ。","ENG":"...If this isn't urgent, get lost already.","TWN":"……沒事的話就快走吧！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그 왜 있잖아요, 머리에 이상한 접시 달고 다니는 여자애.","JPN":"用事はちゃんとあります。あの子ですよ、頭に変な皿をつけてる女の子。","ENG":"Well, you know, the girl with the weird plates on her head?","TWN":"我是說真的啦！頭上掛著奇怪盤子的女生！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>호라이즌</color> 말이군.","JPN":"……<color=#ffd34c>ホライズン</color>のことか。","ENG":"You mean… <color=#ffd34c>Horizon</color>.","TWN":"……你是說<color=#ffd34c>地平線</color>喔？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};